window.docContents[224].resolve({"/#Pro-___tale-cohomology":{"contents":"This blueprint tracks the formalisation of (pro)étale cohomology in Lean,\nfollowing the paper The pro-étale topology for schemes by Bhatt and Scholze.\nA long-term goal of the project is Theorem 5.6.2 of that paper, comparing\nétale and pro-étale cohomology with -coefficients\nfor varieties over an algebraically closed field.\n\n\n\n\n\n\n\n","context":"","header":"Pro-étale cohomology","id":"/#Pro-___tale-cohomology"}});